def _evict_lru(self) -> None:
    """Evict the least recently used entry."""
    if not self._cache:
        return
    # Evict 10% of cache to amortize eviction cost
    entries = sorted(self._cache.items(), key=lambda kv: kv[1].last_access)
    evict_count = max(1, len(self._cache) // 10)
    for key, _ in entries[:evict_count]:
        del self._cache[key]

